here is a temporary workaround, hope you can make sense of it:

```js
async convertXlsToCsv(xlsBuffer) {
        const workbook = new ExcelJS.Workbook();
        await workbook.xlsx.load(xlsBuffer);

        const csvBuffer = await workbook.csv.writeBuffer({
            formatterOptions: {
                transform: (row) => {
                    // this is a scary workaround, i know, but it works
                    const expectedRowLength = COLUMNS_LENGTH;
                    if (row.length < expectedRowLength) {
                        row.length = expectedRowLength;
                        return row.fill(row.length, row.length + 1);
                    }

                    return row;
                },
            },
        });

        return csvBuffer;
}
```

